public class PollingWorker {

    private final long intervalMs;

    public PollingWorker(long intervalMs) {
        this.intervalMs = intervalMs;
    }

    public void runLoop() {
        while (true) {
            try {
                Thread.sleep(intervalMs);
                poll();
            } catch (InterruptedException ex) {
            }
        }
    }

    private void poll() {
    }
}
